framework_css:
/*
  Design system and layout extracted from reference header/footer image
  - Dark red to black gradient header band
  - Heavy, all-caps navigation in a condensed sans-serif
  - High-contrast white type with yellow accent for highlighted nav item
  - Black footer band with thin light divider and compact nav links
*/

:root {
  /* Color palette */
  --color-primary-deep: #2B0000; /* deep maroon from header */
  --color-primary-bright: #5A0000; /* brighter right-side maroon */
  --color-secondary-white: #FFFFFF;
  --color-secondary-red: #C41F26; /* accent red from registration text */
  --color-accent-gold: #D1C400; /* highlighted nav item */

  --color-neutral-black: #000000;
  --color-neutral-white: #FFFFFF;
  --color-neutral-muted: #B0B0B0;

  --color-success: #2E7D32;
  --color-error: #D32F2F;
  --color-warning: #FFA000;
  --color-info: #0288D1;

  /* Typography */
  --font-heading: 'Oswald', Helvetica, sans-serif;
  --font-body: 'Source Sans 3', Arial, sans-serif;

  --font-size-h1: 40px;
  --font-size-h2: 32px;
  --font-size-h3: 24px;
  --font-size-body: 16px;
  --font-size-small: 14px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  /* Spacing scale (4px base increments) */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  /* Layout */
  --site-max-width: 1200px;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body.site {
  min-height: 100vh;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-secondary-white);
  background-color: var(--color-neutral-black);
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:focus-visible {
  outline: 2px solid var(--color-accent-gold);
  outline-offset: 2px;
}

.site-header {
  background-color: var(--color-neutral-black);
}

.header-gradient-band {
  background: linear-gradient(90deg, #000000 0%, var(--color-primary-deep) 35%, var(--color-primary-bright) 100%);
}

.header-inner {
  max-width: var(--site-max-width);
  margin: 0 auto;
  padding: var(--space-5) var(--space-5) var(--space-6);
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: var(--space-5);
}

.brand {
  flex: 0 0 auto;
  display: flex;
  align-items: flex-start;
}

.brand-link {
  display: inline-flex;
}

.brand-mark {
  width: 220px;
  max-width: 35vw;
}

.primary-nav {
  flex: 1 1 auto;
  display: flex;
  justify-content: flex-end;
}

.primary-nav-list {
  list-style: none;
  margin: 0;
  padding: var(--space-2) 0 0;
  display: flex;
  flex-wrap: wrap;
  justify-content: flex-end;
  gap: var(--space-4) var(--space-5);
}

.primary-nav-item {
  flex: 0 0 auto;
}

.primary-nav-link {
  display: inline-block;
  position: relative;
  padding: 6px 0; /* tight vertical spacing as in design */
  font-family: var(--font-heading);
  font-weight: var(--font-weight-semibold);
  text-transform: uppercase;
  letter-spacing: 0.12em;
  font-size: 14px;
  color: var(--color-secondary-white);
  white-space: nowrap;
  transition: color 0.18s ease-out;
}

.primary-nav-link::after {
  content: '';
  position: absolute;
  left: 0;
  right: 0;
  bottom: 0;
  height: 2px;
  background-color: transparent;
  transition: background-color 0.18s ease-out;
}

.primary-nav-link:hover,
.primary-nav-link:focus-visible {
  color: var(--color-accent-gold);
}

.primary-nav-link:hover::after,
.primary-nav-link:focus-visible::after {
  background-color: var(--color-accent-gold);
}

/* Highlighted nav item analogous to REGISTER in the reference */
.primary-nav-link--cta {
  color: var(--color-accent-gold);
}

.primary-nav-link--cta::after {
  background-color: var(--color-accent-gold);
}

.site-main {
  max-width: var(--site-max-width);
  margin: 0 auto;
  padding: var(--space-6) var(--space-5);
}

.site-footer {
  background-color: var(--color-neutral-black);
  color: var(--color-neutral-muted);
}

.footer-inner {
  max-width: var(--site-max-width);
  margin: 0 auto;
  padding: var(--space-5) var(--space-5) var(--space-6);
}

.footer-nav {
  margin-bottom: var(--space-4);
}

.footer-nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-2) var(--space-4);
}

.footer-nav-item {
  flex: 0 0 auto;
}

.footer-nav-link {
  font-family: var(--font-heading);
  font-size: 12px;
  text-transform: uppercase;
  letter-spacing: 0.14em;
  color: var(--color-neutral-muted);
  padding: 4px 0;
  transition: color 0.18s ease-out;
}

.footer-nav-link:hover,
.footer-nav-link:focus-visible {
  color: var(--color-secondary-red);
}

.footer-meta {
  margin-top: var(--space-3);
  margin-bottom: var(--space-3);
  font-size: 13px;
  color: var(--color-secondary-red);
  text-align: center;
  font-family: var(--font-heading);
  text-transform: uppercase;
  letter-spacing: 0.18em;
}

.footer-meta-item--league {
  font-weight: var(--font-weight-semibold);
}

.footer-meta-separator {
  margin: 0 var(--space-2);
}

.footer-divider {
  border: 0;
  border-top: 1px solid rgba(255, 255, 255, 0.18);
  margin: var(--space-3) 0 var(--space-2);
}

.footer-copy {
  margin: 0;
  font-size: 12px;
  text-align: center;
  color: var(--color-neutral-muted);
}

.footer-year {
  color: var(--color-secondary-red);
}

/* Basic responsive adjustments */

@media (max-width: 900px) {
  .header-inner {
    flex-direction: column;
    align-items: center;
    text-align: center;
  }

  .brand-mark {
    width: 190px;
    margin-bottom: var(--space-4);
  }

  .primary-nav-list {
    justify-content: center;
    gap: var(--space-3) var(--space-4);
  }

  .site-main {
    padding-inline: var(--space-3);
  }

  .footer-inner {
    padding-inline: var(--space-3);
  }

  .footer-nav-list {
    justify-content: center;
  }
}

@media (max-width: 600px) {
  .primary-nav-list {
    flex-direction: column;
    align-items: center;
    gap: var(--space-2);
  }

  .primary-nav-link {
    font-size: 13px;
  }

  .footer-nav-list {
    flex-direction: column;
    align-items: center;
    text-align: center;
  }
}
